import Anthropic from '@anthropic-ai/sdk'

export const config = {
  api: {
    bodyParser: {
      sizeLimit: '10mb'
    }
  }
}

if (!process.env.ANTHROPIC_API_KEY) {
  console.error('[api/analyze] ANTHROPIC_API_KEY is not set â all POST requests will return 500')
}

const SUBMIT_TASK_TOOL = {
  name: 'submit_task',
  description: 'Submit the structured task extracted from the worker voice note and/or photo.',
  input_schema: {
    type: 'object',
    properties: {
      task_title: {
        type: 'string',
        description: 'Short task title in English, max 60 characters'
      },
      category: {
        type: 'string',
        enum: ['electrical', 'plumbing', 'structural', 'materials', 'safety', 'inspection', 'other']
      },
      materials_requested: {
        type: 'array',
        items: { type: 'string' },
        description: 'Materials or tools mentioned. Empty array if none.'
      },
      urgency: {
        type: 'string',
        enum: ['low', 'medium', 'high', 'critical']
      },
      summary: {
        type: 'string',
        description: '2-3 sentence summary in English'
      }
    },
    required: ['task_title', 'category', 'materials_requested', 'urgency', 'summary']
  }
}

const SYSTEM_PROMPT = `You are an assistant for construction site management.
A worker has recorded a voice note or photographed a problem on-site.
Extract structured task information using the submit_task tool.
Always respond in English regardless of the worker's input language.
task_title and summary must be in English â translate if necessary.
If no voice transcript is provided, infer all fields from the image.
If the image is ambiguous, set urgency to medium and note uncertainty in summary.
When both an image and text description are provided, treat them as complementary
sources of equal weight. Do not let a vague text description override clear
visual evidence in the image.
Be concise and practical. Assume construction context for ambiguous terms.`

const MAX_REQUESTS = 50
let requestCount = 0
let resetTime = Date.now() + 12 * 60 * 60 * 1000

const cors = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'POST, GET, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type'
}

function setCors(res) {
  Object.entries(cors).forEach(([k, v]) => res.setHeader(k, v))
}

export default async function handler(req, res) {
  setCors(res)

  if (req.method === 'OPTIONS') {
    res.status(204).end()
    return
  }

  if (req.method === 'GET') {
    res.status(200).json({
      count: requestCount,
      max: MAX_REQUESTS,
      remaining: Math.max(0, MAX_REQUESTS - requestCount)
    })
    return
  }

  if (req.method !== 'POST') {
    res.status(405).json({ error: 'Method not allowed' })
    return
  }

  if (!process.env.ANTHROPIC_API_KEY) {
    res.status(500).json({ error: 'Server misconfiguration' })
    return
  }

  try {
    // Step 1 â Cap check
    if (Date.now() > resetTime) {
      requestCount = 0
      resetTime = Date.now() + 12 * 60 * 60 * 1000
    }
    requestCount++
    if (requestCount > MAX_REQUESTS) {
      res.status(429).json({ error: 'Demo limit reached.' })
      return
    }

    // Step 2 â Parse body
    const { text, lat, lng, timestamp, image, locationLabel, worker_id, site_id } = req.body
    if ((!text || !text.trim()) && !image) {
      res.status(400).json({ error: 'Text or photo required.' })
      return
    }

    // Step 3 â Sanitise text
    const safeText = text ? text.slice(0, 2000).trim() : ''
    const sanitised = safeText.replace(/`/g, "'").replace(/\\/g, ' ')

    // Step 4 â Build submitted_at and maps_link
    const submittedAt = new Date().toISOString()
    const maps_link = (lat != null && lng != null)
      ? `https://maps.google.com/?q=${lat},${lng}`
      : null

    // Step 5 â Build user message
    const textBlock = {
      type: 'text',
      text: [
        sanitised ? `Worker voice note: "${sanitised}"` : 'No voice transcript provided.',
        `Recorded at: ${timestamp || submittedAt}`,
        `GPS: ${lat != null ? `${lat}, ${lng}` : 'Not available'}`,
        '',
        'Extract the structured task using the submit_task tool.'
      ].join('\n')
    }

    let userContent
    if (image) {
      userContent = [
        { type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data: image } },
        textBlock
      ]
    } else {
      userContent = [textBlock]
    }

    // Step 6 â Call Anthropic
    const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY })
    const aiResponse = await client.messages.create({
      model: 'claude-haiku-4-5',
      max_tokens: 1024,
      system: SYSTEM_PROMPT,
      messages: [{ role: 'user', content: userContent }],
      tools: [SUBMIT_TASK_TOOL],
      tool_choice: { type: 'tool', name: 'submit_task' }
    })

    // Step 7 â Extract result (.input is already an object â no JSON.parse)
    const toolUse = aiResponse.content.find(b => b.type === 'tool_use')
    if (!toolUse) throw new Error('No tool_use block in Anthropic response')
    const analysis = toolUse.input

    // Step 8 â Build webhook payload
    const finalPayload = {
      meta: {
        worker_id: worker_id ?? null,
        site_id: site_id ?? null,
        coordinates: lat != null ? { lat, lng } : null,
        location_label: locationLabel ?? null,
        maps_link: (lat != null && lng != null)
  ? `https://maps.google.com/?q=${lat},${lng}`
  : null,
        submitted_at: submittedAt,
      },
      task: analysis,
      raw_transcript: sanitised,
      image: image || null
    }

    // Step 9 â Await webhook (not fire-and-forget)
    let webhook_ok = false
    if (process.env.MAKE_WEBHOOK_URL) {
      try {
        const wh = await fetch(process.env.MAKE_WEBHOOK_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(finalPayload)
        })
        webhook_ok = wh.ok
        if (!wh.ok) console.warn('[webhook] Non-OK response:', wh.status)
      } catch (err) {
        console.error('[webhook] Failed:', err.message)
        webhook_ok = false
      }
    } else {
      console.warn('[webhook] MAKE_WEBHOOK_URL not set â skipping')
    }

    // Step 10 â Return full envelope
    res.status(200).json({
      meta: finalPayload.meta,
      task: analysis,
      webhook_ok,
      transcript: sanitised
    })

  } catch (err) {
    console.error('[api/analyze]', err.message)
    res.status(500).json({ error: 'Internal server error.' })
  }
}

export const config = { api: { bodyParser: false } }

if (!process.env.OPENAI_API_KEY) {
  console.error('[api/transcribe] OPENAI_API_KEY is not set â all POST requests will return 500')
}

const cors = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, X-Audio-Duration'
}

const MIME_TO_EXT = {
  'audio/webm': 'webm',
  'audio/webm;codecs=opus': 'webm',
  'audio/ogg': 'ogg',
  'audio/ogg;codecs=opus': 'ogg',
  'audio/mp4': 'mp4',
  'audio/mpeg': 'mp3',
  'audio/wav': 'wav',
  'audio/x-wav': 'wav'
}

function setCors(res) {
  Object.entries(cors).forEach(([k, v]) => res.setHeader(k, v))
}

export default async function handler(req, res) {
  setCors(res)

  if (req.method === 'OPTIONS') {
    res.status(204).end()
    return
  }

  if (req.method !== 'POST') {
    res.status(405).json({ error: 'Method not allowed' })
    return
  }

  // Step 1 â API key check
  if (!process.env.OPENAI_API_KEY) {
    console.error('[transcribe] OPENAI_API_KEY not set')
    res.status(500).json({ error: 'Server misconfiguration' })
    return
  }

  try {
    // Step 2 â Size guard
    const contentLength = parseInt(req.headers['content-length'] || '0', 10)
    if (contentLength > 10 * 1024 * 1024) {
      res.status(413).json({ error: 'Audio file too large. Maximum 10MB.' })
      return
    }

    // Step 3 â Read MIME type
    const mimeType = req.headers['content-type'] || 'audio/webm'

    // Step 4 â Read audio body (Vercel provides raw Buffer via req.body when bodyParser disabled)
    const audioBuffer = await new Promise((resolve, reject) => {
      const chunks = []
      req.on('data', chunk => chunks.push(chunk))
      req.on('end', () => resolve(Buffer.concat(chunks)))
      req.on('error', reject)
    })

    if (!audioBuffer || audioBuffer.length === 0) {
      res.status(400).json({ error: 'Empty audio body.' })
      return
    }

    // Step 5 â Determine file extension for Whisper filename
    const baseMime = mimeType.split(';')[0].trim().toLowerCase()
    const ext = MIME_TO_EXT[baseMime] || MIME_TO_EXT[mimeType.toLowerCase()] || 'webm'

    // Step 6 â Build multipart/form-data for Whisper
    const formData = new FormData()
    formData.append('file', new Blob([audioBuffer], { type: mimeType }), `audio.${ext}`)
    formData.append('model', 'whisper-1')
    formData.append('response_format', 'verbose_json')

    // Step 7 â Call OpenAI Whisper
    const whisperRes = await fetch('https://api.openai.com/v1/audio/transcriptions', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.OPENAI_API_KEY}`
        // Do NOT set Content-Type â fetch sets it automatically with boundary
      },
      body: formData
    })

    if (!whisperRes.ok) {
      const errBody = await whisperRes.text()
      console.error('[transcribe] Whisper error:', whisperRes.status, errBody)
      res.status(502).json({ error: 'Transcription service error. Please try again.' })
      return
    }

    // Step 8 â Parse response
    const whisperData = await whisperRes.json()
    const transcript = whisperData.text?.trim() || ''
    const detected_language = whisperData.language || 'en'

    // Step 9 â Return result (empty transcript is valid â photo-only path)
    res.status(200).json({ transcript, detected_language })

  } catch (err) {
    console.error('[transcribe]', err.message)
    res.status(500).json({ error: 'Internal transcription error.' })
  }
}

