const LOADING_TIMEOUT_MS = 4000
const RETRY_DELAY_MS = 3000
const RESTART_COOLDOWN_MS = 2000
const SEND_HARD_TIMEOUT_MS = 12000
const GPS_CONFIRM_WAIT_MS = 3000
const MAX_RECORDING_SECONDS = 30
