        `${d.count} / ${d.max}`
    })
    .catch(() => {})
}

async function fetchWithRetry(url, options, retries = 1, delayMs = RETRY_DELAY_MS) {
  try {
    const res = await fetch(url, options)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    return res
  } catch (err) {
    if (retries > 0) {
      await new Promise(r => setTimeout(r, delayMs))
      return fetchWithRetry(url, options, retries - 1, delayMs)
    }
    throw err
  }
}

// FileReader-based compression â avoids createImageBitmap Safari compat issues
async function compressImage(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onerror = () => reject(new Error('FileReader failed'))
    reader.onload = (e) => {
      const img = new Image()
      img.onerror = () => reject(new Error('Image load failed'))
      img.onload = () => {
        const canvas = document.createElement('canvas')
        const scale = Math.min(1, 800 / img.width)
        canvas.width = Math.round(img.width * scale)
        canvas.height = Math.round(img.height * scale)
        canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height)
        canvas.toBlob(
          blob => blob ? resolve(blob) : reject(new Error('toBlob failed')),
          'image/jpeg',
          0.7
        )
      }
      img.src = e.target.result
    }
    reader.readAsDataURL(file)
  })
}

async function blobToBase64(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => resolve(reader.result.split(',')[1])
    reader.onerror = reject
    reader.readAsDataURL(blob)
  })
}

function sanitize(text) {
  return text.slice(0, 2000).trim().replace(/`/g, "'").replace(/\\/g, ' ')
}

// Reverse geocode lat/lng to a human-readable address label
async function reverseGeocode(lat, lng) {
  try {
    const res = await fetch(
      `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lng=${lng}&format=json&accept-language=en`,
      { headers: { 'User-Agent': 'SiteSpeak-AI/1.0' } }
    )
    if (!res.ok) return null
    const data = await res.json()
    return data.display_name?.split(',').slice(0, 3).join(', ') ?? null
  } catch {
    return null
  }
}

async function handlePhotoChange(e) {
  const file = e.target.files[0]
  if (!file) { clearPhoto(); return }
  try {
    const compressed = await compressImage(file)
    appState.photoBlob = compressed
    appState.photoBase64 = await blobToBase64(compressed)
    const s1 = document.getElementById('photo-status')
    if (s1) s1.textContent = 'â Photo selected'
    document.body.classList.add('has-photo')
  } catch (err) {
    console.error('[photo]', err.message)
    clearPhoto()
  }
}

function clearPhoto() {
  appState.photoBlob = null
  appState.photoBase64 = null
  const s1 = document.getElementById('photo-status')
  if (s1) s1.textContent = 'Add photo'
  document.body.classList.remove('has-photo')
}

function parseIdentityFromURL() {
  const params = new URLSearchParams(window.location.search)
  appState.worker_id = params.get('worker') || null
  appState.site_id = params.get('site') || null

  if (!appState.worker_id && !appState.site_id) {
    document.body.dataset.identity = 'none'
  } else {
    delete document.body.dataset.identity
  }
}

function initGeolocation() {
  appState.gpsState = 'pending'
  if (navigator.geolocation) {
    navigator.geolocation.getCurrentPosition(
      pos => {
        appState.lat = pos.coords.latitude
        appState.lng = pos.coords.longitude
        appState.gpsState = 'resolved'
        reverseGeocode(appState.lat, appState.lng)
          .then(label => { appState.locationLabel = label })
          .catch(() => { appState.locationLabel = null })
      },
      () => {
        appState.gpsState = 'failed'
        appState.lat = null
        appState.lng = null
      },
      { timeout: 10000, maximumAge: 60000 }
    )
  } else {
    appState.gpsState = 'failed'
  }
}

function getSupportedMimeType() {
  const types = [
    'audio/webm;codecs=opus',
    'audio/webm',
    'audio/ogg;codecs=opus',
    'audio/ogg',
    'audio/mp4'
  ]
  for (const type of types) {
    if (MediaRecorder.isTypeSupported(type)) return type
  }
  return null
}

async function startRecording() {
  // Step 1 â Get mic permission
  let stream
  try {
    stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false })
  } catch (err) {
    document.getElementById('error-message').textContent =
      err.name === 'NotAllowedError'
        ? 'Microphone access denied. Please allow microphone access and try again.'
        : `Microphone error: ${err.message}`
    setState('error')
    return
  }

  // Step 2 â Get MIME type
  const mimeType = getSupportedMimeType()
  if (!mimeType) {
    document.getElementById('error-message').textContent =
      'Your browser does not support audio recording. Please use Chrome or Safari.'
    setState('error')
    stream.getTracks().forEach(t => t.stop())
    return
  }
  appState.audioMimeType = mimeType

  // Step 3 â Set up MediaRecorder
  appState.audioChunks = []
  appState.mediaRecorder = new MediaRecorder(stream, { mimeType })

  appState.mediaRecorder.ondataavailable = e => {
    if (e.data.size > 0) appState.audioChunks.push(e.data)
  }

  appState.mediaRecorder.onerror = e => {
    console.error('[recorder]', e.error)
    stream.getTracks().forEach(t => t.stop())
    document.getElementById('error-message').textContent =
      'Recording error. Please try again.'
    setState('error')
  }

  appState.mediaRecorder.onstop = () => {
    stream.getTracks().forEach(t => t.stop())
    handleRecordingComplete()
  }

  // Step 4 â Start recording
  appState.timestamp = new Date().toISOString()
  appState.mediaRecorder.start()
  setState('recording')
  navigator.vibrate?.(80)
  setStatus('RECORDING...')
  animateButtonRecord(document.getElementById('record-btn'))

  // Step 5 â Auto-stop after MAX_RECORDING_SECONDS
  appState._recordingTimer = setTimeout(() => {
    if (appState.mediaRecorder?.state === 'recording') {
      appState.mediaRecorder.stop()
    }
  }, MAX_RECORDING_SECONDS * 1000)
}

function stopRecording() {
  if (appState._recordingTimer) {
    clearTimeout(appState._recordingTimer)
    appState._recordingTimer = null
  }
  if (appState.mediaRecorder?.state === 'recording') {
    appState.mediaRecorder.stop()  // triggers onstop â handleRecordingComplete
  }
}

async function handleRecordingComplete() {
  // Step 1 â Build audio blob
  const audioBlob = new Blob(appState.audioChunks, { type: appState.audioMimeType })
  if (audioBlob.size === 0) {
    setStatus('No audio recorded. Please try again.')
    setState('idle')
    return
  }

  // Step 2 â Client-side size check
  if (audioBlob.size > 5 * 1024 * 1024) {
    document.getElementById('error-message').textContent =
      'Recording too long. Maximum 30 seconds.'
    setState('error')
    return
  }

  // Step 3 â Show transcribing state
  setState('transcribing')
  document.getElementById('transcribing-hint').textContent = 'Transcribing...'
  setStatus('TRANSCRIBING...')

  // Step 4 â Send to /api/transcribe
  let transcriptResult
  try {
    const res = await fetch(TRANSCRIBE_ENDPOINT, {
      method: 'POST',
      headers: {
        'Content-Type': appState.audioMimeType,
        'X-Audio-Duration': String(MAX_RECORDING_SECONDS)
      },
      body: audioBlob
    })
    if (!res.ok) {
      const errData = await res.json().catch(() => ({}))
      throw new Error(errData.error || `Transcription failed: HTTP ${res.status}`)
    }
    transcriptResult = await res.json()
  } catch (err) {
    console.error('[app] transcription error:', err.message)
    document.getElementById('error-message').textContent =
      `Could not transcribe audio: ${err.message}`
    setState('error')
    document.getElementById('transcribing-hint').textContent = ''
    return
  }

  // Step 5 â Store results
  appState.transcript = transcriptResult.transcript || ''
  appState.detectedLanguage = transcriptResult.detected_language || 'en'
  document.getElementById('transcribing-hint').textContent = ''

  // Step 6 â Check for empty transcript (photo-only path valid when image attached)
  if (!appState.transcript && !appState.photoBase64) {
    setStatus('No speech detected. Please try again or add a photo.')
    setState('idle')
    return
  }

  // Step 7 â Enter confirming
  navigator.vibrate?.([40, 30, 40])
  enterConfirming()
}

function toggleRecording() {
  if (document.body.dataset.state === 'idle') startRecording()
  else if (document.body.dataset.state === 'recording') stopRecording()
}

function renderConfirmMap() {
  const mapImg = document.getElementById('confirm-map-img')
  const mapUnavail = document.getElementById('confirm-map-unavailable')
  const gpsEl = document.getElementById('confirm-gps')

  if (!mapImg || !mapUnavail) return

  if (appState.lat !== null && appState.lng !== null) {
    const lat = appState.lat
    const lng = appState.lng
    const apiKey = document.documentElement.dataset.gmapsKey || ''

    if (apiKey) {
      const size = '400x180'
      const zoom = 16
      const marker = `color:red|${lat},${lng}`
      const src = `https://maps.googleapis.com/maps/api/staticmap` +
        `?center=${lat},${lng}&zoom=${zoom}&size=${size}` +
        `&markers=${encodeURIComponent(marker)}&key=${apiKey}`
      mapImg.src = src
      mapImg.style.display = 'block'
      mapUnavail.style.display = 'none'
      if (gpsEl) gpsEl.textContent =
        appState.locationLabel || `${lat.toFixed(4)}, ${lng.toFixed(4)}`
    } else {
      // No API key â show coordinates text only
      mapImg.style.display = 'none'
      mapUnavail.style.display = 'none'
      if (gpsEl) gpsEl.textContent =
        appState.locationLabel || `${lat.toFixed(4)}, ${lng.toFixed(4)}`
    }
  } else {
    // GPS unavailable
    mapImg.style.display = 'none'
    mapUnavail.style.display = 'block'
    if (gpsEl) gpsEl.textContent = ''
  }
}

// enterConfirming â GPS timing gate + confirm panel population
async function enterConfirming() {
  // Wait for GPS if still pending (max GPS_CONFIRM_WAIT_MS)
  if (appState.gpsState === 'pending') {
    setStatus('Getting location...')
    await new Promise(resolve => {
      const interval = setInterval(() => {
        if (appState.gpsState !== 'pending') {
          clearInterval(interval)
          resolve()
        }
      }, 100)
      setTimeout(() => {
        clearInterval(interval)
        resolve()
      }, GPS_CONFIRM_WAIT_MS)
    })
  }

  setState('confirming')
  animateButtonIdle(document.getElementById('record-btn'))

  // Photo preview
  const preview = document.getElementById('confirm-photo-preview')
  const noneEl = document.getElementById('confirm-photo-none')
  if (appState.photoBlob) {
    preview.src = URL.createObjectURL(appState.photoBlob)
    preview.style.display = 'block'
    if (noneEl) noneEl.style.display = 'none'
    document.body.classList.add('has-photo')
  } else {
    preview.style.display = 'none'
    if (noneEl) noneEl.style.display = 'block'
    document.body.classList.remove('has-photo')
  }

  // Transcript
  document.getElementById('confirm-transcript').textContent =
    appState.transcript || '(No transcript â photo only)'

  // Identity
  const workerEl = document.getElementById('confirm-worker')
  const siteEl = document.getElementById('confirm-site')
  if (workerEl) workerEl.textContent = appState.worker_id ? `Worker: ${appState.worker_id}` : ''
  if (siteEl) siteEl.textContent = appState.site_id ? `Site: ${appState.site_id}` : ''

  // Map + GPS
  renderConfirmMap()

  animatePanelIn('#confirm-panel')
}

function renderResultCard(task, rawTranscript) {
  appState.lastTask = task

  const badge = document.getElementById('result-urgency-badge')
  if (badge) {
    badge.textContent = URGENCY_LABELS[task.urgency] ?? task.urgency.toUpperCase()
    badge.className = `urgency-${task.urgency}`
  }

  const title = document.getElementById('result-title')
  if (title) title.textContent = task.task_title ?? ''

  const category = document.getElementById('result-category')
  if (category) category.textContent = CATEGORY_LABELS[task.category] ?? task.category

  const materialsRow = document.getElementById('result-materials-row')
  const materialsContainer = document.getElementById('result-materials')
  if (materialsContainer) {
    materialsContainer.innerHTML = ''
    if (task.materials_requested && task.materials_requested.length > 0) {
      task.materials_requested.forEach(m => {
        const pill = document.createElement('span')
        pill.className = 'material-pill'
        pill.textContent = m
        materialsContainer.appendChild(pill)
      })
      if (materialsRow) materialsRow.style.display = 'flex'
    } else {
      if (materialsRow) materialsRow.style.display = 'none'
    }
  }

  const summary = document.getElementById('result-summary')
  if (summary) summary.textContent = task.summary ?? ''

  const transcriptRow = document.getElementById('result-transcript-row')
  const transcriptEl = document.getElementById('result-transcript')
  if (transcriptEl) {
    if (rawTranscript) {
      transcriptEl.textContent = rawTranscript
      if (transcriptRow) transcriptRow.classList.add('visible')
    } else {
      if (transcriptRow) transcriptRow.classList.remove('visible')
    }
  }

  const trelloNote = document.getElementById('result-trello-note')
  if (trelloNote) trelloNote.textContent = 'Sent to Trello in English'
}

// sendNote â AbortController + hard timeout race + identity in body
async function sendNote() {
  setState('sending')
  document.getElementById('send-btn').disabled = true
  document.getElementById('discard-btn').disabled = true
  setStatus('SENDING...')
  window.speechSynthesis.cancel()

  const loadingEl = document.getElementById('loading-text')
  const loadingTimer = setTimeout(() => {
    if (loadingEl) loadingEl.textContent = 'Still processing...'
  }, LOADING_TIMEOUT_MS)

  try {
    const sanitised = sanitize(appState.transcript || '')

    appState.abortController = new AbortController()

    const body = {
      text: sanitised,
      lat: appState.lat,
      lng: appState.lng,
      timestamp: appState.timestamp,
      image: appState.photoBase64 || null,
      locationLabel: appState.locationLabel ?? null,
      worker_id: appState.worker_id,
      site_id: appState.site_id
    }

    const timeoutPromise = new Promise((_, reject) =>
      setTimeout(() => reject(new Error('Send timeout')), SEND_HARD_TIMEOUT_MS)
    )

    const response = await Promise.race([
      fetchWithRetry('/api/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
        signal: appState.abortController.signal
      }),
      timeoutPromise
    ])

    appState.abortController = null
    clearTimeout(loadingTimer)
    if (loadingEl) loadingEl.textContent = ''

    const data = await response.json()

    renderResultCard(data.task, data.transcript)

    const webhookEl = document.getElementById('webhook-status')
    if (webhookEl) {
      webhookEl.textContent = data.webhook_ok ? WEBHOOK_LABEL_SUCCESS : WEBHOOK_LABEL_FAILURE
      webhookEl.className = data.webhook_ok ? 'webhook-ok' : 'webhook-fail'
    }

    await animatePanelOut('#confirm-panel')
    setState('done')
    await animatePanelIn('#result-panel')
    animateResultCascade(document.getElementById('result-card'))
    animateSendSuccess()
    refreshUsageCounter()

  } catch (err) {
    clearTimeout(loadingTimer)
    if (loadingEl) loadingEl.textContent = ''
    console.error('[sendNote]', err.message)
    document.getElementById('error-message').textContent =
      'Could not connect. Please try again.'
    setState('error')
  }
}

// clearAppState â abort in-flight request; preserves GPS, identity across submissions
function clearAppState() {
  if (appState.abortController) {
    appState.abortController.abort()
    appState.abortController = null
  }

  if (appState.mediaRecorder?.state === 'recording') {
    appState.mediaRecorder.stop()
  }
  appState.mediaRecorder = null
  appState.audioChunks = []
  appState.audioMimeType = ''
  appState.detectedLanguage = 'en'
  if (appState._recordingTimer) {
    clearTimeout(appState._recordingTimer)
    appState._recordingTimer = null
  }

  appState.transcript = ''
  appState.timestamp = null
  appState.lastTask = null
  clearPhoto()

  const photoInput = document.getElementById('photo-input')
  if (photoInput) photoInput.value = ''
  const photoInputConfirm = document.getElementById('photo-input-confirm')
  if (photoInputConfirm) photoInputConfirm.value = ''

  document.getElementById('confirm-transcript').textContent = ''
  document.getElementById('confirm-gps').textContent = ''
  document.getElementById('error-message').textContent = ''
  document.getElementById('transcribing-hint').textContent = ''

  const mapImg = document.getElementById('confirm-map-img')
  if (mapImg) mapImg.style.display = 'none'
  const mapUnavail = document.getElementById('confirm-map-unavailable')
  if (mapUnavail) mapUnavail.style.display = 'none'

  const transcriptRow = document.getElementById('result-transcript-row')
  if (transcriptRow) transcriptRow.classList.remove('visible')

  const webhookEl = document.getElementById('webhook-status')
  if (webhookEl) { webhookEl.textContent = ''; webhookEl.className = '' }
  const loadingEl = document.getElementById('loading-text')
  if (loadingEl) loadingEl.textContent = ''

  document.getElementById('send-btn').disabled = false
  document.getElementById('discard-btn').disabled = false

  const restartBtn = document.getElementById('restart-btn')
  const errorRestartBtn = document.getElementById('error-restart-btn')
  if (restartBtn) {
    restartBtn.disabled = true
    setTimeout(() => { restartBtn.disabled = false }, RESTART_COOLDOWN_MS)
  }
  if (errorRestartBtn) {
    errorRestartBtn.disabled = true
    setTimeout(() => { errorRestartBtn.disabled = false }, RESTART_COOLDOWN_MS)
  }

  setStatus('READY')
  window.speechSynthesis.cancel()
  // lat, lng, gpsState, locationLabel, worker_id, site_id are NOT reset â
  // GPS is cached from page load; identity is set once from the QR code URL
}

document.addEventListener('DOMContentLoaded', () => {
  // 1. Parse identity from URL
  parseIdentityFromURL()

  // 2. Request GPS on load (cached; never requested again)
  initGeolocation()

  // 3. Wire record button
  document.getElementById('record-btn').addEventListener('click', toggleRecording)

  // 4. Wire shared buttons
  document.getElementById('send-btn').addEventListener('click', sendNote)
  document.getElementById('discard-btn').addEventListener('click', () => {
    clearAppState(); setState('idle')
  })
  document.getElementById('restart-btn').addEventListener('click', () => {
    clearAppState(); setState('idle')
  })
  document.getElementById('error-restart-btn').addEventListener('click', () => {
    clearAppState(); setState('idle')
  })

  // 5. Photo inputs
  document.getElementById('photo-input').addEventListener('change', handlePhotoChange)
  const photoInputConfirm = document.getElementById('photo-input-confirm')
  if (photoInputConfirm) {
    photoInputConfirm.addEventListener('change', async (e) => {
      await handlePhotoChange(e)
      if (appState.photoBlob) {
        const preview = document.getElementById('confirm-photo-preview')
        if (preview) {
          preview.src = URL.createObjectURL(appState.photoBlob)
          preview.style.display = 'block'
        }
        const noneEl = document.getElementById('confirm-photo-none')
        if (noneEl) noneEl.style.display = 'none'
        document.body.classList.add('has-photo')
      }
    })
  }

  // 6. Logo tap resets to idle
  const logoBlock = document.getElementById('logo-block')
  if (logoBlock) {
    logoBlock.addEventListener('click', () => { clearAppState(); setState('idle') })
    logoBlock.style.cursor = 'pointer'
  }

  // 7. Readback button â user-triggered, no auto-play; iOS requires user gesture
  const readbackBtn = document.getElementById('readback-btn')
  if (readbackBtn) {
    readbackBtn.addEventListener('click', () => {
      if (!appState.transcript) return
      try {
        window.speechSynthesis.cancel()
        const utt = new SpeechSynthesisUtterance(appState.transcript)
        utt.lang = appState.detectedLanguage || 'en'
        utt.rate = 0.9
        window.speechSynthesis.speak(utt)
      } catch (_) {}
    })
  }

  // 8. visibilitychange guard
  document.addEventListener('visibilitychange', () => {
    if (!document.hidden) return
    window.speechSynthesis.cancel()
    const state = document.body.dataset.state
    if (state === 'recording') {
      stopRecording()
      // onstop fires â handleRecordingComplete â enterConfirming or idle
    }
    // All other states: preserve
  })

  // 9. Initial usage counter
  refreshUsageCounter()

  // 10. Register service worker
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('/sw.js').catch(err => {
      console.warn('[sw] Registration failed:', err.message)
    })
  }

  // 11. Set initial state
  setState('idle')
  animateLoadIn()
})

// @motionone/dom â stable vanilla ES module build. CDN failure degrades to no-op.
let _animate = null

async function getAnimate() {
  if (_animate !== null) return _animate
  try {
    const mod = await import('https://cdn.jsdelivr.net/npm/@motionone/dom@latest/dist/index.es.js')
    _animate = mod.animate
  } catch (_) {
    _animate = () => {}
  }
  return _animate
}

// GSAP lazy loader â CDN failure safe
let _gsap = null

async function getGSAP() {
  if (_gsap !== null) return _gsap
  try {
    await new Promise((resolve, reject) => {
      const script = document.createElement('script')
      script.src = 'https://cdn.jsdelivr.net/npm/gsap@3.12.5/dist/gsap.min.js'
      script.onload = resolve
      script.onerror = reject
      document.head.appendChild(script)
    })
    _gsap = window.gsap || null
  } catch (_) {
    _gsap = null
  }
  return _gsap
}

export async function animateButtonRecord(el) {
  if (!el) return
  try {
    const gsap = await getGSAP()
    if (gsap) {
      gsap.to(el, {
        scale: 0.96,
        duration: 0.12,
        ease: 'power2.out',
        yoyo: true,
        repeat: 1
      })
    }
  } catch (_) {}
}

export async function animateButtonIdle(el) {
  if (!el) return
  try {
    const gsap = await getGSAP()
    if (gsap) {
      gsap.to(el, { scale: 1, duration: 0.3, ease: 'elastic.out(1, 0.5)' })
    }
  } catch (_) {}
}

export async function animatePanelIn(selector) {
  const el = typeof selector === 'string'
    ? document.querySelector(selector) : selector
  if (!el) return
  try {
    const gsap = await getGSAP()
    if (gsap) {
      gsap.fromTo(
        el.children,
        { opacity: 0, y: 14 },
        {
          opacity: 1, y: 0,
          duration: 0.35,
          ease: 'power2.out',
          stagger: 0.055,
          clearProps: 'transform'
        }
      )
    }
    // CSS animation handles the panel-in fallback
  } catch (_) {}
}

export async function animatePanelOut(selector) {
  const el = typeof selector === 'string'
    ? document.querySelector(selector) : selector
  if (!el) return
  try {
    const gsap = await getGSAP()
    if (gsap) {
      await new Promise(resolve => {
        gsap.to(el, {
          opacity: 0, y: -10,
          duration: 0.22,
          ease: 'power2.in',
          onComplete: resolve
        })
      })
    }
  } catch (_) {}
}

export async function animateResultCascade(el) {
  if (!el) return
  try {
    const gsap = await getGSAP()
    if (!gsap) {
      // Fallback: simple opacity fade
      const animate = await getAnimate()
      animate(el, { opacity: [0, 1] }, { duration: 0.4 })
      return
    }

    const badge    = el.querySelector('#result-urgency-badge')
    const title    = el.querySelector('#result-title')
    const children = Array.from(el.children).filter(
      c => c !== badge && c !== title
    )

    if (badge) {
      gsap.fromTo(badge,
        { scale: 0, opacity: 0 },
        { scale: 1, opacity: 1, duration: 0.45,
          ease: 'elastic.out(1, 0.5)', delay: 0.05 }
      )
    }

    if (title) {
      gsap.fromTo(title,
        { opacity: 0, y: 10 },
        { opacity: 1, y: 0, duration: 0.4, ease: 'power3.out', delay: 0.2 }
      )
    }

    if (children.length) {
      gsap.fromTo(children,
        { opacity: 0, y: 8 },
        {
          opacity: 1, y: 0,
          duration: 0.35,
          ease: 'power2.out',
          stagger: 0.07,
          delay: 0.35,
          clearProps: 'transform'
        }
      )
    }
  } catch (_) {}
}

export async function animateSendSuccess() {
  try {
    const gsap = await getGSAP()
    const flash = document.createElement('div')
    Object.assign(flash.style, {
      position: 'fixed',
      inset: '0',
      background: 'var(--color-accent)',
      opacity: '0',
      zIndex: '9999',
      pointerEvents: 'none'
    })
    document.body.appendChild(flash)

    if (gsap) {
      gsap.timeline({ onComplete: () => flash.remove() })
        .to(flash, { opacity: 0.18, duration: 0.08, ease: 'power2.out' })
        .to(flash, { opacity: 0,    duration: 0.55, ease: 'power2.in' })
    } else {
      // CSS transition fallback
      flash.style.transition = 'opacity 600ms ease'
      requestAnimationFrame(() => {
        flash.style.opacity = '0.18'
        setTimeout(() => {
          flash.style.opacity = '0'
          setTimeout(() => flash.remove(), 600)
        }, 80)
      })
    }
  } catch (_) {}
}

export async function animateLoadIn() {
  try {
    const gsap = await getGSAP()
    if (!gsap) return
    const targets = ['#header', '#voice-mode', '#status-bar']
      .map(s => document.querySelector(s))
      .filter(Boolean)
    gsap.fromTo(
      targets,
      { opacity: 0, y: 20 },
      {
        opacity: 1, y: 0,
        duration: 0.5,
        ease: 'power2.out',
        stagger: 0.1,
        delay: 0.1,
        clearProps: 'transform'
      }
    )
  } catch (_) {}
}

export async function animateStatusUpdate(el) {
  if (!el) return
  try {
    const gsap = await getGSAP()
    if (!gsap) return
    gsap.fromTo(el,
      { opacity: 0.2 },
      { opacity: 1, duration: 0.25, ease: 'power2.out' }
    )
  } catch (_) {}
}

:root {
