  --color-surface-raised:#222222;
  --color-surface-overlay: rgba(255, 255, 255, 0.03);
  --color-accent:        #FFD600;
  --color-accent-dim:    rgba(255, 214, 0, 0.12);
  --color-text:          #E8E8E8;
  --color-text-muted:    #777777;
  --color-active:        #00FF41;
  --color-error:         #FF4444;
  --color-border:        #2e2e2e;
  --color-border-accent: #FFD600;
  --color-on-accent:     #111111;
  --color-on-error:      #ffffff;
  --font-display:        'Barlow Condensed', sans-serif;
  --font-mono:           'DM Mono', 'Courier New', monospace;
  --space-xs:            4px;
  --space-sm:            8px;
  --space-md:            16px;
  --space-lg:            24px;
  --space-xl:            40px;
  --space-2xl:           64px;
  --btn-record-size:     168px;
  --btn-record-border:   2px;
  --radius:              3px;
  --radius-sm:           2px;
  --border-width:        2px;
  --transition-fast:     100ms ease;
  --transition-base:     220ms ease;
  --transition-slow:     380ms ease;
  --map-height:          180px;
  --grain-opacity:       0.035;
  /* Glow system */
  --glow-accent:         0 0 20px rgba(255, 214, 0, 0.25),
                         0 0 40px rgba(255, 214, 0, 0.08);
  --glow-active:         0 0 16px rgba(0, 255, 65, 0.3);
  --glow-error:          0 0 16px rgba(255, 68, 68, 0.25);
  /* Urgency */
  --color-urgency-high:        #FF8C00;
  --color-urgency-high-bg:     rgba(255, 140, 0, 0.15);
  --color-urgency-critical:    #FF4444;
  --color-urgency-critical-bg: rgba(255, 68, 68, 0.15);
  --color-urgency-medium:      #FFD600;
  --color-urgency-medium-bg:   rgba(255, 214, 0, 0.12);
