/* âââ Reset ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ */

*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

html {
  font-size: 16px;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

button, label {
  touch-action: manipulation;
}

/* âââ Body â scanline via background-image âââââââââââââââââââââââââââââââ */

body {
  background-color: var(--color-bg);
  color: var(--color-text);
  font-family: var(--font-display);
  min-height: 100dvh;
  overflow-x: hidden;
  background-image:
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      rgba(255,255,255,0.008) 2px,
      rgba(255,255,255,0.008) 4px
    );
}

/* âââ App âââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ */

#app {
  min-height: 100dvh;
  display: flex;
  flex-direction: column;
  max-width: 480px;
  margin: 0 auto;
  position: relative;
  user-select: none;
  -webkit-user-select: none;
}

/* Grain overlay */
#app::before {
  content: '';
  position: fixed;
  inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='1'/%3E%3C/svg%3E");
  opacity: var(--grain-opacity);
  pointer-events: none;
  z-index: 9998;
}

/* âââ Header ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ */

