/* âââ Record animations âââââââââââââââââââââââââââââââââââââââââââââââââââ */

@keyframes pulse-record {
  0%, 49%   { opacity: 1; }
  50%, 100% { opacity: 0.45; }
}

@keyframes waveform-dance {
  0%   { transform: translateX(-50%) scaleY(1); }
  100% { transform: translateX(-50%) scaleY(1.5); }
}

