/* âââ Confirm panel âââââââââââââââââââââââââââââââââââââââââââââââââââââââ */

#confirm-panel {
  display: none;
  flex-direction: column;
  gap: var(--space-md);
  padding: var(--space-lg);
  flex: 1;
}

body[data-state="confirming"] #confirm-panel,
body[data-state="sending"] #confirm-panel {
  display: flex;
  animation: panel-in 300ms cubic-bezier(0.22, 1, 0.36, 1) both;
}

body[data-state="sending"] #confirm-actions {
  pointer-events: none;
  opacity: 0.45;
}

body[data-state="confirming"] #confirm-loading,
body[data-state="confirming"] #confirm-map-unavailable {
  display: none;
}

body[data-state="sending"] #confirm-loading {
  display: block;
}

/* Confirm data cards */
#confirm-identity-block,
#confirm-photo-block,
#confirm-transcript-block,
#confirm-gps-block,
#confirm-map-block {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: var(--space-md);
  position: relative;
  border-left: 2px solid var(--color-border-accent);
}

#confirm-identity-block p,
#confirm-gps-block p {
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--color-text);
  line-height: 1.6;
}

#confirm-gps {
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--color-active);
  letter-spacing: 0.04em;
}

#confirm-transcript {
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.7;
  color: var(--color-text);
