import {
  animateButtonRecord,
  animateButtonIdle,
  animatePanelIn,
  animatePanelOut,
  animateResultCascade,
  animateSendSuccess,
  animateLoadIn,
  animateStatusUpdate
} from './motion.js'

const appState = {
  transcript: '',
  lat: null,
  lng: null,
  timestamp: null,
  photoBlob: null,
  photoBase64: null,
  gpsState: 'pending',      // 'pending' | 'resolved' | 'failed'
  locationLabel: null,      // string from Nominatim, or null
  abortController: null,    // AbortController for in-flight fetch
  lastTask: null,
  worker_id: null,
  site_id: null,
  detectedLanguage: 'en',
  mediaRecorder: null,
  audioChunks: [],
  audioMimeType: '',
  _recordingTimer: null
}

const WEBHOOK_LABEL_SUCCESS = 'â Sent to Trello'
const WEBHOOK_LABEL_FAILURE = 'â  Webhook delivery failed'
const LOADING_TIMEOUT_MS = 4000
const RETRY_DELAY_MS = 3000
const RESTART_COOLDOWN_MS = 2000
const SEND_HARD_TIMEOUT_MS = 12000
const GPS_CONFIRM_WAIT_MS = 3000
const MAX_RECORDING_SECONDS = 30
const TRANSCRIBE_ENDPOINT = '/api/transcribe'

const CATEGORY_LABELS = {
  electrical:  'Electrical',
  plumbing:    'Plumbing',
  structural:  'Structural',
  materials:   'Materials',
  safety:      'Safety',
  inspection:  'Inspection',
  other:       'Other'
}

const URGENCY_LABELS = {
  low:      'LOW',
  medium:   'MEDIUM',
  high:     'HIGH',
  critical: 'CRITICAL'
}

function setState(name) { document.body.dataset.state = name }
function setStatus(text) {
  const el = document.getElementById('status-text')
  el.textContent = text
  animateStatusUpdate(el)
}

function refreshUsageCounter() {
  fetch('/api/analyze')
    .then(r => r.json())
    .then(d => {
      document.getElementById('usage-counter').textContent =
        `${d.count} / ${d.max}`
    })
    .catch(() => {})
}

async function fetchWithRetry(url, options, retries = 1, delayMs = RETRY_DELAY_MS) {
  try {
    const res = await fetch(url, options)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    return res
  } catch (err) {
    if (retries > 0) {
      await new Promise(r => setTimeout(r, delayMs))
      return fetchWithRetry(url, options, retries - 1, delayMs)
    }
    throw err
  }
}

// FileReader-based compression â avoids createImageBitmap Safari compat issues
async function compressImage(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onerror = () => reject(new Error('FileReader failed'))
    reader.onload = (e) => {
      const img = new Image()
      img.onerror = () => reject(new Error('Image load failed'))
      img.onload = () => {
        const canvas = document.createElement('canvas')
        const scale = Math.min(1, 800 / img.width)
        canvas.width = Math.round(img.width * scale)
        canvas.height = Math.round(img.height * scale)
        canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height)
        canvas.toBlob(
          blob => blob ? resolve(blob) : reject(new Error('toBlob failed')),
          'image/jpeg',
          0.7
        )
      }
      img.src = e.target.result
    }
    reader.readAsDataURL(file)
  })
}

async function blobToBase64(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => resolve(reader.result.split(',')[1])
    reader.onerror = reject
    reader.readAsDataURL(blob)
  })
}

function sanitize(text) {
  return text.slice(0, 2000).trim().replace(/`/g, "'").replace(/\\/g, ' ')
}

// Reverse geocode lat/lng to a human-readable address label
async function reverseGeocode(lat, lng) {
  try {
    const res = await fetch(
      `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lng=${lng}&format=json&accept-language=en`,
      { headers: { 'User-Agent': 'SiteSpeak-AI/1.0' } }
    )
    if (!res.ok) return null
    const data = await res.json()
    return data.display_name?.split(',').slice(0, 3).join(', ') ?? null
  } catch {
    return null
  }
}

async function handlePhotoChange(e) {
  const file = e.target.files[0]
  if (!file) { clearPhoto(); return }
  try {
    const compressed = await compressImage(file)
    appState.photoBlob = compressed
    appState.photoBase64 = await blobToBase64(compressed)
    const s1 = document.getElementById('photo-status')
    if (s1) s1.textContent = 'â Photo selected'
    document.body.classList.add('has-photo')
  } catch (err) {
    console.error('[photo]', err.message)
    clearPhoto()
  }
}

function clearPhoto() {
  appState.photoBlob = null
  appState.photoBase64 = null
  const s1 = document.getElementById('photo-status')
  if (s1) s1.textContent = 'Add photo'
