// sendNote â AbortController + hard timeout race + identity in body
async function sendNote() {
  setState('sending')
  document.getElementById('send-btn').disabled = true
  document.getElementById('discard-btn').disabled = true
  setStatus('SENDING...')
  window.speechSynthesis.cancel()

  const loadingEl = document.getElementById('loading-text')
  const loadingTimer = setTimeout(() => {
    if (loadingEl) loadingEl.textContent = 'Still processing...'
  }, LOADING_TIMEOUT_MS)

  try {
    const sanitised = sanitize(appState.transcript || '')

    appState.abortController = new AbortController()

    const body = {
      text: sanitised,
      lat: appState.lat,
      lng: appState.lng,
      timestamp: appState.timestamp,
      image: appState.photoBase64 || null,
      locationLabel: appState.locationLabel ?? null,
      worker_id: appState.worker_id,
      site_id: appState.site_id
    }

    const timeoutPromise = new Promise((_, reject) =>
      setTimeout(() => reject(new Error('Send timeout')), SEND_HARD_TIMEOUT_MS)
    )

    const response = await Promise.race([
      fetchWithRetry('/api/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
        signal: appState.abortController.signal
      }),
      timeoutPromise
    ])

    appState.abortController = null
    clearTimeout(loadingTimer)
    if (loadingEl) loadingEl.textContent = ''

    const data = await response.json()

    renderResultCard(data.task, data.transcript)

    const webhookEl = document.getElementById('webhook-status')
    if (webhookEl) {
      webhookEl.textContent = data.webhook_ok ? WEBHOOK_LABEL_SUCCESS : WEBHOOK_LABEL_FAILURE
      webhookEl.className = data.webhook_ok ? 'webhook-ok' : 'webhook-fail'
    }

    await animatePanelOut('#confirm-panel')
    setState('done')
    await animatePanelIn('#result-panel')
    animateResultCascade(document.getElementById('result-card'))
    animateSendSuccess()
    refreshUsageCounter()

  } catch (err) {
    clearTimeout(loadingTimer)
    if (loadingEl) loadingEl.textContent = ''
    console.error('[sendNote]', err.message)
    document.getElementById('error-message').textContent =
      'Could not connect. Please try again.'
    setState('error')
  }
}

// clearAppState â abort in-flight request; preserves GPS, identity across submissions
function clearAppState() {
  if (appState.abortController) {
    appState.abortController.abort()
    appState.abortController = null
  }

  if (appState.mediaRecorder?.state === 'recording') {
    appState.mediaRecorder.stop()
  }
  appState.mediaRecorder = null
  appState.audioChunks = []
  appState.audioMimeType = ''
  appState.detectedLanguage = 'en'
  if (appState._recordingTimer) {
    clearTimeout(appState._recordingTimer)
    appState._recordingTimer = null
  }

  appState.transcript = ''
  appState.timestamp = null
  appState.lastTask = null
  clearPhoto()

  const photoInput = document.getElementById('photo-input')
  if (photoInput) photoInput.value = ''
  const photoInputConfirm = document.getElementById('photo-input-confirm')
  if (photoInputConfirm) photoInputConfirm.value = ''

  document.getElementById('confirm-transcript').textContent = ''
  document.getElementById('confirm-gps').textContent = ''
  document.getElementById('error-message').textContent = ''
  document.getElementById('transcribing-hint').textContent = ''

  const mapImg = document.getElementById('confirm-map-img')
  if (mapImg) mapImg.style.display = 'none'
  const mapUnavail = document.getElementById('confirm-map-unavailable')
  if (mapUnavail) mapUnavail.style.display = 'none'

  const transcriptRow = document.getElementById('result-transcript-row')
  if (transcriptRow) transcriptRow.classList.remove('visible')

  const webhookEl = document.getElementById('webhook-status')
  if (webhookEl) { webhookEl.textContent = ''; webhookEl.className = '' }
  const loadingEl = document.getElementById('loading-text')
  if (loadingEl) loadingEl.textContent = ''

  document.getElementById('send-btn').disabled = false
  document.getElementById('discard-btn').disabled = false

  const restartBtn = document.getElementById('restart-btn')
  const errorRestartBtn = document.getElementById('error-restart-btn')
  if (restartBtn) {
    restartBtn.disabled = true
    setTimeout(() => { restartBtn.disabled = false }, RESTART_COOLDOWN_MS)
  }
  if (errorRestartBtn) {
    errorRestartBtn.disabled = true
    setTimeout(() => { errorRestartBtn.disabled = false }, RESTART_COOLDOWN_MS)
  }

  setStatus('READY')
  window.speechSynthesis.cancel()
  // lat, lng, gpsState, locationLabel, worker_id, site_id are NOT reset â
  // GPS is cached from page load; identity is set once from the QR code URL
}

document.addEventListener('DOMContentLoaded', () => {
  // 1. Parse identity from URL
  parseIdentityFromURL()

  // 2. Request GPS on load (cached; never requested again)
  initGeolocation()

  // 3. Wire record button
  document.getElementById('record-btn').addEventListener('click', toggleRecording)

  // 4. Wire shared buttons
  document.getElementById('send-btn').addEventListener('click', sendNote)
  document.getElementById('discard-btn').addEventListener('click', () => {
    clearAppState(); setState('idle')
  })
  document.getElementById('restart-btn').addEventListener('click', () => {
    clearAppState(); setState('idle')
  })
  document.getElementById('error-restart-btn').addEventListener('click', () => {
    clearAppState(); setState('idle')
  })

  // 5. Photo inputs
  document.getElementById('photo-input').addEventListener('change', handlePhotoChange)
  const photoInputConfirm = document.getElementById('photo-input-confirm')
  if (photoInputConfirm) {
    photoInputConfirm.addEventListener('change', async (e) => {
      await handlePhotoChange(e)
      if (appState.photoBlob) {
        const preview = document.getElementById('confirm-photo-preview')
        if (preview) {
          preview.src = URL.createObjectURL(appState.photoBlob)
          preview.style.display = 'block'
        }
        const noneEl = document.getElementById('confirm-photo-none')
        if (noneEl) noneEl.style.display = 'none'
        document.body.classList.add('has-photo')
      }
    })
  }

  // 6. Logo tap resets to idle
  const logoBlock = document.getElementById('logo-block')
  if (logoBlock) {
    logoBlock.addEventListener('click', () => { clearAppState(); setState('idle') })
    logoBlock.style.cursor = 'pointer'
  }

  // 7. Readback button â user-triggered, no auto-play; iOS requires user gesture
  const readbackBtn = document.getElementById('readback-btn')
  if (readbackBtn) {
    readbackBtn.addEventListener('click', () => {
      if (!appState.transcript) return
      try {
        window.speechSynthesis.cancel()
        const utt = new SpeechSynthesisUtterance(appState.transcript)
        utt.lang = appState.detectedLanguage || 'en'
        utt.rate = 0.9
        window.speechSynthesis.speak(utt)
      } catch (_) {}
    })
  }

  // 8. visibilitychange guard
  document.addEventListener('visibilitychange', () => {
    if (!document.hidden) return
    window.speechSynthesis.cancel()
    const state = document.body.dataset.state
    if (state === 'recording') {
      stopRecording()
      // onstop fires â handleRecordingComplete â enterConfirming or idle
    }
    // All other states: preserve
  })

  // 9. Initial usage counter
  refreshUsageCounter()

  // 10. Register service worker
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('/sw.js').catch(err => {
      console.warn('[sw] Registration failed:', err.message)
    })
  }

  // 11. Set initial state
  setState('idle')
  animateLoadIn()
})

