        { type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data: image } },
        textBlock
      ]
    } else {
      userContent = [textBlock]
    }

    // Step 6 â Call Anthropic
    const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY })
    const aiResponse = await client.messages.create({
      model: 'claude-haiku-4-5',
      max_tokens: 1024,
      system: SYSTEM_PROMPT,
      messages: [{ role: 'user', content: userContent }],
      tools: [SUBMIT_TASK_TOOL],
      tool_choice: { type: 'tool', name: 'submit_task' }
    })

    // Step 7 â Extract result (.input is already an object â no JSON.parse)
    const toolUse = aiResponse.content.find(b => b.type === 'tool_use')
    if (!toolUse) throw new Error('No tool_use block in Anthropic response')
    const analysis = toolUse.input

    // Step 8 â Build webhook payload
    const finalPayload = {
      meta: {
        worker_id: worker_id ?? null,
        site_id: site_id ?? null,
        coordinates: lat != null ? { lat, lng } : null,
        location_label: locationLabel ?? null,
        maps_link: (lat != null && lng != null)
